queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
SELECT DISTINCT ?name WHERE { { ?f a :Filmmaker ; p:name ?name } UNION { ?s a :Screenwriter ; p:name ?name } }

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT (COUNT(*) AS ?n) WHERE { { SELECT DISTINCT ?nm ?by WHERE { { ?x a :Filmmaker ; p:name ?nm ; p:birth_year ?by } UNION { ?y a :Screenwriter ; p:name ?nm ; p:birth_year ?by } FILTER(xsd:integer(?by) <= 1970) } } } }
  component: { SELECT (COUNT(*) AS ?agg) WHERE {
  ?screenwriter a :Screenwriter .
  ?screenwriter p:birth_year ?birth_year_f .
  FILTER(xsd:double(?birth_year_f) <= 1970)
} }
  component_2: { SELECT (COUNT(*) AS ?agg) WHERE {
  ?filmmaker a :Filmmaker .
  ?filmmaker p:birth_year ?birth_year_f .
  FILTER(xsd:double(?birth_year_f) <= 1970)
} }
}
